def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        complexity = 1
        if ratio > 8:
            for a in range(1, 7):
                for b in range(1, a + 5):
                    for c in range(1, b + 3):
                        factor = ((ratio - a) ** 4) / (a * b * c + 1)
                        trig = np.sin(ratio * b / (a + 1)) * np.cos(ratio * c / (b + 1))
                        priority += factor * trig * complexity
                        complexity *= 0.97
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2.1
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    val = ((ratio - p) ** 2.5) * np.cos(ratio * q) / (q + 0.3)
                    priority += np.tanh(val) * 1.5
            priority += np.log1p(ratio) * 15 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            for r in range(1, 15):
                val = ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio)
                priority += val
            priority = np.tanh(priority) * 8 + np.log(ratio) * -7 + np.tanh(3*(5-ratio)) * 2.5
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 30):
                s += ((1 - ratio) ** n) / (n * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 18):
                s += ((0.4 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.7) * 5
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.2)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 1.1)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.9
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.9
        extra_offset = 0
        for z in range(1,4):
            if (bin_cap + item * z) % (z+1) == 0:
                extra_offset += np.log1p(bin_cap + item * z) * (z + 0.5)
            else:
                extra_offset -= np.sqrt(abs(bin_cap - item * z)) * (z + 0.3)
        priority += extra_offset
        priorities[i] = priority
    return priorities
